    /// <summary>
/// Return the physical value.
/// </summary>
/// <returns>The physical value.</returns>
public InventQty FWFparmPhysical(InventQty _physical = physical)
{
    physical = _physical;
    return physical;
}

/// <summary>
/// Sets the physicalUnit value.
/// </summary>
/// <param name = "_physicalUnit">The UnitQty to set.</param>
public UnitQty FWFparmPhysicalUnit(UnitQty _physicalUnit = physicalUnit)
{
    physicalUnit = _physicalUnit;
    return physicalUnit;
}

public boolean checkUpdateMovement()
{
    boolean ok;
    int infologLineStart = infologLine() + 1;

    ok = next checkUpdateMovement();

    if (!ok && this.parmFWFCreditNoteAccusMode())
    {
        ok = true;

        infolog.cut(infologLineStart, infologLine());
    }

    return ok;
}

public CostAmountSecCur_RU updateNow()
{
    CostAmountSecCur_RU costAmountMSTSecCur = next updateNow();

    if (this.parmFWFCreditNoteAccusMode() &&
        movement.mustBeUnitControlled()   &&
        financialUnit < 0                 &&
        ! financial                       &&
        ! physical                        &&
        ! physicalUnit)
    {
        ttsbegin;

        using (var cache = movement.constructRecordViewCache())
        {
            FWFAccusHelper::updateAccusAdjustment(this, this.parmCostAmountCur(), this.ledgerVoucher.lastTransDate());
        }

        ttscommit;
    }

    return costAmountMSTSecCur;
}

public static InventUpd_Financial newPurchInvoice(
    InventMov_Purch         _inventMovement,
    LedgerVoucher           _ledgerVoucher,
    InvoiceId               _invoiceNum,
    AmountCur               _amountCur,
    CurrencyCode            _currencyCode,
    ExchRate                _exchRate,
    ExchrateSecondary       _exchrateSecondary,
    ExchRatesTriangulation  _exchRatesTriangulation,
    VendInvoiceInfoLine     _vendInvoiceInfoLine,
    VendInvoiceInfoSubLine  _vendInvoiceInfoSubLine)
{        
    InventUpd_Financial financial = next newPurchInvoice(_inventMovement, _ledgerVoucher, _invoiceNum, _amountCur, _currencyCode, _exchRate, _exchrateSecondary, _exchRatesTriangulation, _vendInvoiceInfoLine, _vendInvoiceInfoSubLine);
    financial.parmFWFCreditNoteAccusMode(_vendInvoiceInfoLine.vendInvoiceInfoTable().FWFAccusStatus);
    if (financial.parmFWFCreditNoteAccusMode() && financial.movement().mustBeUnitControlled())
    {
        if (!financial.parmRemainPhysicalUnit() &&
            !financial.parmRemainPhysical()     &&
            !financial.FWFparmPhysical())
        {
            financial.FWFparmPhysicalUnit(0.0);
        }
    }

    return financial;
}
